namespace HON.Orders.Data
{
  public class AppDbContext : DbContext
  {
    public DbSet<Customer> Customers { get; set; }
    public DbSet<Product> Products { get; set; }
    public DbSet<Order> Orders { get; set; }
    public DbSet<OrderItem> OrderItems { get; set; }
    public DbSet<Payment> Payments { get; set; }
    public DbSet<AuditLog> AuditLogs { get; set; }

    public AppDbContext(DbContextOptions<AppDbContext> options)
      : base(options)
    {
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
      base.OnModelCreating(modelBuilder);

      modelBuilder.Entity<Customer>()
        .HasIndex(c => c.Email)
        .IsUnique();

      modelBuilder.Entity<Product>()
        .Property(p => p.UnitPrice)
        .HasPrecision(18, 2);

      modelBuilder.Entity<Product>()
        .Property(p => p.RowVersion)
        .IsRowVersion();

      modelBuilder.Entity<Order>()
        .HasIndex(o => o.OrderNumber)
        .IsUnique();

      modelBuilder.Entity<Order>()
        .Property(o => o.Total)
        .HasPrecision(18, 2);

      modelBuilder.Entity<Order>()
        .Property(o => o.RowVersion)
        .IsRowVersion();

      modelBuilder.Entity<Order>()
        .HasOne(o => o.Customer)
        .WithMany(c => c.Orders)
        .HasForeignKey(o => o.CustomerId)
        .OnDelete(DeleteBehavior.Cascade);

      modelBuilder.Entity<OrderItem>()
        .HasOne(oi => oi.Order)
        .WithMany(o => o.OrderItems)
        .HasForeignKey(oi => oi.OrderId)
        .OnDelete(DeleteBehavior.Cascade);

      modelBuilder.Entity<OrderItem>()
        .HasOne(oi => oi.Product)
        .WithMany(p => p.OrderItems)
        .HasForeignKey(oi => oi.ProductId);

      modelBuilder.Entity<Payment>()
        .HasOne(p => p.Order)
        .WithMany(o => o.Payments)
        .HasForeignKey(p => p.OrderId)
        .OnDelete(DeleteBehavior.Cascade);

      modelBuilder.Entity<Customer>().HasQueryFilter(c => !c.IsDeleted);
      modelBuilder.Entity<Product>().HasQueryFilter(p => !p.IsDeleted);
      modelBuilder.Entity<Order>().HasQueryFilter(o => !o.IsDeleted);
      modelBuilder.Entity<OrderItem>().HasQueryFilter(oi => !oi.IsDeleted);
      modelBuilder.Entity<Payment>().HasQueryFilter(p => !p.IsDeleted);

      foreach (var entity in modelBuilder.Model.GetEntityTypes())
      {
        modelBuilder.Entity(entity.ClrType)
          .Property<DateTime>("CreatedAt")
          .HasDefaultValueSql("GETUTCDATE()");

        modelBuilder.Entity(entity.ClrType)
          .Property<DateTime>("LastModifiedAt")
          .HasDefaultValueSql("GETUTCDATE()");
      }
    }
  }

  public interface IHasSoftDelete
  {
    bool IsDeleted { get; set; }
  }
}

namespace HON.Orders.Domain.Services
{
  public class OrderService
  {
    private readonly AppDbContext _context;

    public OrderService(AppDbContext context)
    {
      _context = context;
    }

    public IEnumerable<TopCustomerDto> GetTopCustomersByRevenue(int days = 30, int topCount = 5)
    {
      var since = DateTime.UtcNow.AddDays(-days);

      return _context.Orders
        .Where(o => o.OrderDate >= since)
        .Include(o => o.OrderItems)
        .GroupBy(o => o.Customer)
        .Select(g => new TopCustomerDto
        {
          CustomerName = g.Key.Name,
          OrdersCount = g.Count(),
          Revenue = g.SelectMany(o => o.OrderItems)
            .Sum(oi => oi.LineTotal)
        })
        .OrderByDescending(x => x.Revenue)
        .Take(topCount)
        .ToList();
    }

    public async IAsyncEnumerable<Order> StreamOrdersAsync(
      DateTime since,
      int pageSize = 20,
      [EnumeratorCancellation] CancellationToken ct = default)
    {
      int skip = 0;

      while (true)
      {
        var orders = await _context.Orders
          .Where(o => o.OrderDate >= since)
          .OrderByDescending(o => o.OrderDate)
          .Include(o => o.Customer)
          .Include(o => o.OrderItems)
          .Skip(skip)
          .Take(pageSize)
          .ToListAsync(ct);

        if (!orders.Any())
          break;

        foreach (var order in orders)
          yield return order;

        skip += pageSize;
      }
    }
  }

  public class TopCustomerDto
  {
    public string CustomerName { get; set; }
    public int OrdersCount { get; set; }
    public decimal Revenue { get; set; }
  }
}

